<?php
namespace App\Models\Crm; use App\Enums\Crm\ProformaStatus; use App\Models\User; use Illuminate\Database\Eloquent\Attributes\Fillable; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\HasMany;
#[Fillable(['company_id','customer_id','lead_id','quotation_id','proforma_number','title','customer_name','customer_company','customer_email','customer_phone','billing_address','currency','subtotal','discount_total','tax_total','grand_total','paid_amount','balance_amount','invoice_date','due_date','status','public_token','public_url','notes','terms_conditions','internal_remarks','sent_at','paid_at','cancelled_at','created_by','updated_by'])]
class CrmProformaInvoice extends Model { protected function casts():array{return ['status'=>ProformaStatus::class,'subtotal'=>'decimal:2','discount_total'=>'decimal:2','tax_total'=>'decimal:2','grand_total'=>'decimal:2','paid_amount'=>'decimal:2','balance_amount'=>'decimal:2','invoice_date'=>'date','due_date'=>'date','sent_at'=>'datetime','paid_at'=>'datetime','cancelled_at'=>'datetime'];} public function lead():BelongsTo{return $this->belongsTo(CrmLead::class);} public function customer():BelongsTo{return $this->belongsTo(CrmCustomer::class);} public function quotation():BelongsTo{return $this->belongsTo(CrmQuotation::class);} public function onboarding():HasMany{return $this->hasMany(CrmCustomerOnboarding::class,'proforma_invoice_id')->latest('created_at');} public function items():HasMany{return $this->hasMany(CrmProformaInvoiceItem::class,'proforma_invoice_id')->orderBy('sort_order');} public function payments():HasMany{return $this->hasMany(CrmProformaPayment::class,'proforma_invoice_id')->latest('payment_date');} public function shares():HasMany{return $this->hasMany(CrmProformaShare::class,'proforma_invoice_id')->latest('created_at');} public function supportTickets():HasMany{return $this->hasMany(CrmSupportTicket::class,'proforma_invoice_id')->latest('updated_at');} public function creator():BelongsTo{return $this->belongsTo(User::class,'created_by');} }
